mapper.select:
SELECT pi.product_id, p.product_name, p.unit, pi.lot_no, GREATEST( pi.inbound_qty - IFNULL(( SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no ), 0), 0 ) AS stock_qty, 50 AS safe_qty, pi.reg_date, pi.expire_date FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
ORDER BY pi.reg_date DESC

SELECT COUNT(*) FROM ( SELECT 1 FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id LEFT JOIN product_outbound po ON pi.product_id = po.product_id AND pi.lot_no = po.lot_no
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
GROUP BY pi.product_id, pi.lot_no ) AS tmp

mapper.update:
UPDATE product_stock
SET stock_qty = GREATEST(stock_qty - #{qty}, 0)
WHERE product_id = #{productId} AND lot_no = #{lotNo}

mapper.select:
SELECT reg_date, type, qty, memo
FROM product_stock_transaction
WHERE product_id = #{productId}
  AND lot_no = #{lotNo}
ORDER BY reg_date DESC
